// AI Agent Cost Calculator — Token Usage & Cost Extractor
// Supports: Anthropic Claude, OpenAI, Google Gemini, Perplexity
// To add a new model, add an entry to MODEL_RATES below.

if (Object.keys($json).length === 0) return {};

const usage = $json.data?.resultData?.runData;
const workflowId = $json.workflowId;
const runId = $json.id;

if (!usage) return {};

// ── Model rates (USD per 1M tokens) ─────────────────────────
// Add new models here as providers release them.
// Format: "model-id": { input: $/1M, output: $/1M }
const MODEL_RATES = {
  // ── Anthropic Claude ──
  "claude-opus-4-7":            { input: 5.00,  output: 25.00 },
  "claude-opus-4-6":            { input: 5.00,  output: 25.00 },
  "claude-sonnet-4-6":          { input: 3.00,  output: 15.00 },
  "claude-sonnet-4-5-20250929": { input: 3.00,  output: 15.00 },
  "claude-sonnet-4-5":          { input: 3.00,  output: 15.00 },
  "claude-haiku-4-5-20251001":  { input: 1.00,  output: 5.00  },
  "claude-haiku-4-5":           { input: 1.00,  output: 5.00  },
  "claude-opus-4-5-20251101":   { input: 5.00,  output: 25.00 },
  "claude-opus-4-5":            { input: 5.00,  output: 25.00 },
  "claude-opus-4-1-20250805":   { input: 15.00, output: 75.00 },
  "claude-opus-4-1":            { input: 15.00, output: 75.00 },
  "claude-opus-4-20250514":     { input: 15.00, output: 75.00 },
  "claude-opus-4-0":            { input: 15.00, output: 75.00 },
  "claude-sonnet-4-20250514":   { input: 3.00,  output: 15.00 },
  "claude-sonnet-4-0":          { input: 3.00,  output: 15.00 },
  "claude-3-7-sonnet-20250219": { input: 3.00,  output: 15.00 },
  "claude-3-5-sonnet-20241022": { input: 3.00,  output: 15.00 },
  "claude-3-5-sonnet-20240620": { input: 3.00,  output: 15.00 },
  "claude-3-5-haiku-20241022":  { input: 0.80,  output: 4.00  },
  "claude-3-opus-20240229":     { input: 15.00, output: 75.00 },
  "claude-3-sonnet-20240229":   { input: 3.00,  output: 15.00 },
  "claude-3-haiku-20240307":    { input: 0.25,  output: 1.25  },

  // ── OpenAI ──
  "gpt-4.1":       { input: 2.00,  output: 8.00  },
  "gpt-4.1-mini":  { input: 0.40,  output: 1.60  },
  "gpt-4.1-nano":  { input: 0.10,  output: 0.40  },
  "gpt-4o":        { input: 2.50,  output: 10.00 },
  "gpt-4o-mini":   { input: 0.15,  output: 0.60  },
  "gpt-4-turbo":   { input: 5.00,  output: 15.00 },
  "gpt-4":         { input: 30.00, output: 60.00 },
  "gpt-3.5-turbo": { input: 0.50,  output: 1.50  },
  "o4-mini":       { input: 1.10,  output: 4.40  },
  "o3":            { input: 2.00,  output: 8.00  },
  "o3-mini":       { input: 1.10,  output: 4.40  },
  "o3-pro":        { input: 20.00, output: 80.00 },
  "o1":            { input: 15.00, output: 60.00 },
  "o1-mini":       { input: 1.10,  output: 4.40  },

  // ── Google Gemini ──
  "gemini-2.5-pro":        { input: 1.25,  output: 10.00 },
  "gemini-2.5-flash":      { input: 0.30,  output: 2.50  },
  "gemini-2.5-flash-lite": { input: 0.10,  output: 0.40  },
  "gemini-2.0-flash":      { input: 0.15,  output: 0.60  },
  "gemini-2.0-flash-lite": { input: 0.075, output: 0.30  },
  "gemini-1.5-pro":        { input: 1.25,  output: 5.00  },
  "gemini-1.5-flash":      { input: 0.075, output: 0.30  },
  "gemini-1.5-flash-8b":   { input: 0.0375,output: 0.15  },

  // ── Perplexity ──
  "sonar":               { input: 1.00, output: 1.00  },
  "sonar-pro":           { input: 3.00, output: 15.00 },
  "sonar-reasoning":     { input: 1.00, output: 5.00  },
  "sonar-reasoning-pro": { input: 2.00, output: 8.00  },
};

function calculateCost(model, promptTokens, completionTokens) {
  const rates = MODEL_RATES[model];
  if (!rates) return null;
  const inputCost = (promptTokens / 1000000) * rates.input;
  const outputCost = (completionTokens / 1000000) * rates.output;
  return Math.round((inputCost + outputCost) * 1000000) / 1000000;
}

const receipt = {};
receipt[workflowId] = {};
receipt[workflowId][runId.toString()] = {};

for (const key in usage) {
  if (!Object.prototype.hasOwnProperty.call(usage, key)) continue;
  const steps = usage[key];

  for (const i in steps) {
    try {
      const element = steps[i];
      const elementData = element.data;
      const elementDataOverride = element.inputOverride;

      if (!elementData) continue;

      let model = undefined;
      let tokenData = undefined;

      // LLM nodes: Anthropic, OpenAI, Gemini (ai_languageModel output)
      if (Object.prototype.hasOwnProperty.call(elementData, 'ai_languageModel')) {
        const override = elementDataOverride?.['ai_languageModel']?.[0]?.[0]?.json;
        const output = elementData['ai_languageModel']?.[0]?.[0]?.json;

        model = override?.options?.model
          ?? override?.options?.model_name
          ?? override?.model
          ?? output?.model
          ?? undefined;

        tokenData = output?.tokenUsageEstimate ?? output?.tokenUsage ?? undefined;

      // HTTP/API nodes: Perplexity and other REST-based LLMs
      } else if (Object.prototype.hasOwnProperty.call(elementData, 'main')) {
        const output = elementData['main']?.[0]?.[0]?.json;
        model = output?.model ?? undefined;
        tokenData = output?.usage ?? undefined;
      }

      if (model && tokenData) {
        const pt = tokenData.promptTokens ?? tokenData.prompt_tokens ?? 0;
        const ct = tokenData.completionTokens ?? tokenData.completion_tokens ?? 0;
        const tt = tokenData.totalTokens ?? tokenData.total_tokens ?? (pt + ct);
        const cost = calculateCost(model, pt, ct);

        const existing = receipt[workflowId][runId.toString()][model];
        if (existing && typeof existing === 'object' && existing.promptTokens !== undefined) {
          // Aggregate tokens when same model appears multiple times in one execution
          existing.promptTokens += pt;
          existing.completionTokens += ct;
          existing.totalTokens += tt;
          if (cost !== null) existing.costUSD = (existing.costUSD ?? 0) + cost;
        } else {
          receipt[workflowId][runId.toString()][model] = {
            promptTokens: pt,
            completionTokens: ct,
            totalTokens: tt,
            ...(cost !== null ? { costUSD: cost } : {})
          };
        }
        receipt[workflowId][runId.toString()]['createdAt'] = $json.startedAt ?? "";
      }
    } catch (e) {
      // Skip steps that cannot be parsed
      continue;
    }
  }
}

if (Object.keys(receipt[workflowId][runId.toString()]).length === 0) return {};

return receipt;
